1412	///
1413	/// URL parsing:
1414	///   - The first segment after `<idx>/proof-step/` is the lemma name.
1415	///   - The LAST 1 or 2 segments are the method (e.g. `simplify`,
1416	///     `induction`, `sorry`, `solve/<id>`).
1417	///   - Everything in between is the proof-tree path (case names).
1418	pub async fn proof_step(
1419	    State(state): State<Arc<AppState>>,
1420	    Path((idx, raw_path)): Path<(usize, String)>,
1421	) -> axum::Json<Value> {
1422	    let Some(_entry) = state.store.get(idx) else {
1423	        return json_resp::alert(format!("theory index {} not found", idx));
1424	    };
1425	    // Parse the path: `<lemma>/<case>/.../<method>` or
1426	    // `<lemma>/<case>/.../<method>/<arg>`.  The shared decoder reverses
1427	    // the Haskell `prefixWithUnderscore` invariant per segment.
1428	    let segs: Vec<String> = path_parse::decode_segments(&raw_path);
1429	    if segs.is_empty() {
1430	        return json_resp::alert("missing lemma name");
1431	    }
1432	    let lemma = segs[0].clone();
1433	    // Identify the method head — the last segment is the method
1434	    // unless the second-to-last segment is `solve` (then `solve/<id>`
1435	    // is the method).
1436	    let n = segs.len();
1437	    if n < 2 {
1438	        return json_resp::alert("missing proof method");
1439	    }
1440	    let method_start = if n >= 3 && segs[n - 2] == "solve" { n - 2 } else { n - 1 };
1441	    let case_path: Vec<String> = segs[1..method_start].to_vec();
1442	    let method_segs = &segs[method_start..];
1443	    let ps = match state.store.ensure_proof_state(idx, &state.cfg) {
1444	        Ok(p) => p,
1445	        Err(e) => return json_resp::alert(format!("proof state init failed: {}", e)),
1446	    };
1447	    let sys_at_path = match ps.get_system_at(&lemma, &case_path) {
1448	        Some(s) => s,
1449	        None => return json_resp::alert(format!(
1450	            "no system at path {:?} in lemma {}", case_path, lemma)),
1451	    };
1452	    let method = match crate::handlers::proof_tree::parse_method(method_segs, &sys_at_path) {
1453	        Some(m) => m,
1454	        None => return json_resp::alert(format!(
1455	            "unknown proof method: {:?}", method_segs)),
1456	    };
1457	    match ps.apply_at_path(&lemma, &case_path, method) {
1458	        Ok(_status) => {}
1459	        Err(e) => return json_resp::alert(format!("proof step failed: {}", e)),
1460	    }
1461	    // Re-render the updated proof tree.  Use the sub-proof snippet
1462	    // for the node at `case_path` so the response shows Applicable
1463	    // Proof Methods + Constraint System + N sub-case(s) just like
1464	    // Haskell does.  Append the full proof tree below for navigation.
1465	    let root = match ps.get_root(&lemma) {
1466	        Some(r) => r,
1467	        None => return json_resp::alert("proof tree disappeared"),
1468	    };
1469	    let node = match crate::handlers::proof_tree::navigate_at(&root, &case_path) {
1470	        Some(n) => n,
1471	        None => return json_resp::alert(format!(
1472	            "no node at path {:?} after step", case_path)),
1473	    };
1474	    // Install this lemma's per-lemma `use_induction`/`heuristic` into the
1475	    // shared ctx before ranking the re-rendered snippet (HS `getProofContext`).
1476	    // Also the user-fn thread-locals — the snippet execs candidate methods.
1477	    let _user_funs_guard = ps.install_user_funs();
1478	    let mut ctx_guard = ps.ctx.lock();
1479	    ps.install_lemma_settings(&mut ctx_guard, &lemma);
1480	    let mut html = crate::handlers::proof_tree::render_sub_proof_snippet(
1481	        idx, &lemma, &case_path, node, &ctx_guard);
1482	    drop(ctx_guard);
1483	    html.push_str("<hr><h3>Proof tree</h3>\n");
1484	    html.push_str(&crate::handlers::proof_tree::render_proof_tree_html(
1485	        idx, &lemma, &root));
